te final Map\u003cString, QuickfixjEngine\u003e engines = new HashMap\u003c\u003e();\n45:     private final Map\u003cString, QuickfixjEngine\u003e provisionalEngines = new HashMap\u003c\u003e();\n46:     private final Map\u003cString, QuickfixjEndpoint\u003e endpoints = new HashMap\u003c\u003e();\n47: \n48:     private Map\u003cString, QuickfixjConfiguration\u003e configurations = new HashMap\u003c\u003e();\n49: \n50:     @Metadata(label = \"advanced\")\n51:     private MessageStoreFactory messageStoreFactory;\n52:     @Metadata(label = \"advanced\")\n53:     private LogFactory logFactory;\n54:     @Metadata(label = \"advanced\")\n55:     private MessageFactory messageFactory;\n56:     @Metadata\n57:     private boolean lazyCreateEngines;\n58:     @Metadata(defaultValue = \"true\")\n59:     private boolean eagerStopEngines = true;\n60: \n61:     public QuickfixjComponent() {\n62:     }\n63: \n64:     public QuickfixjComponent(CamelContext context) {\n65:         super(context);\n66:     }\n67: \n68:     @Override\n69:     protected Endpoint createEndpoint(String uri, String remaining, Map\u003cString, Object\u003e parameters) throws Exception {\n70:         // Look up the engine instance based on the settings file (\"remaining\")\n71:         QuickfixjEngine engine;\n72:         lock.lock();\n73:         try {\n74:             QuickfixjEndpoint endpoint = endpoints.get(uri);\n75: \n76:             if (endpoint == null) {\n77:                 engine = engines.get(remaining);\n78:                 if (engine == null) {\n79:                     engine = provisionalEngines.get(remaining);\n80:                 }\n81:                 if (engine == null) {\n82:                     QuickfixjConfiguration configuration = configurations.get(remaining);\n83:                     SessionSettings settings;\n84:                     if (configuration != null) {\n85:                         settings = configuration.createSessionSettings();\n86:                     } else {\n87:                         settings = QuickfixjEngine.loadSettings(getCamelContext(), remaining);\n88:                     }\n89:                     Boolean lazyCreateEngineForEndpoint\n90:                             = super.getAndRemoveParameter(parameters, PARAMETER_LAZY_CREATE_ENGINE, Boolean.TYPE);\n91:                     if (lazyCreateEngineForEndpoint == null) {\n92:                         lazyCreateEngineForEndpoint = isLazyCreateEngines();\n93:                     }\n94:                     engine = new QuickfixjEngine(\n95:                             uri, settings, messageStoreFactory, logFactory, messageFactory,\n96:                             lazyCreateEngineForEndpoint);\n97: \n98:                     // only start engine if CamelContext is already started, otherwise the engines gets started\n99:                     // automatic later when CamelContext has been started using the StartupListener\n100:                     if (getCamelContext().getStatus().isStarted()) {\n101:                         startQuickfixjEngine(engine);\n102:                         engines.put(remaining, engine);\n103:                     } else {\n104:                         // engines to be started later\n105:                         provisionalEngines.put(remaining, engine);\n106:                     }\n107:                 }\n108: \n109:                 endpoint = new QuickfixjEndpoint(engine, uri, this);\n110:                 endpoint.setConfigurationName(remaining);\n111:                 endpoint.setLazyCreateEngine(engine.isLazy());\n112:                 engine.addEventListener(endpoint);\n113:                 endpoints.put(uri, endpoint);\n114:             }\n115: \n116:             return endpoint;\n117:         } finally {\n118:             lock.unlock();\n119:         }\n120:     }\n121: \n122:     @Override\n123:     protected void doStop() throws Exception {\n124:         // stop engines when stopping component\n125:         lock.lock();\n126:         try {\n127:             for (QuickfixjEngine engine : engines.values()) {\n128:                 engine.stop();\n129:             }\n130:         } finally {\n131:             lock.unlock();\n132:         }\n133:         super.doStop();\n134:     }\n135: \n136:     @Override\n137:     protected void doShutdown() throws Exception {\n138:         // cleanup when shutting down\n139:         engines.clear();\n140:         provisionalEngines.clear();\n141:         endpoints.clear();\n142:         super.doShutdown();\n143:     }\n144: \n145:     private void startQuickfixjEngine(QuickfixjEngine engine) {\n146:         if (!engine.isLazy()) {\n147:             LOG.info(\"Starting QuickFIX/J engine: {}\", engine.getUri());\n148:             ServiceHelper.startService(engine);\n149:         } else {\n150:             LOG.info(\"QuickFIX/J engine: {} will start lazily\", engine.getUri());\n151:         }\n152:     }\n153: \n154:     // Test Support\n155:     Map\u003cString, QuickfixjEngine\u003e getEngines() {\n156:         return Collections.unmodifiableMap(engines);\n157:     }\n158: \n159:     // Test Support\n160:     Map\u003cString, QuickfixjEngine\u003e getProvisionalEngines() {\n161:         return Collections.unmodifiableMap(provisionalEngines);\n162:     }\n163: \n164:     /**\n165:      * To use the given MessageFactory\n166:      */\n167:     public void setMessageFactory(MessageFactory messageFactory) {\n168:         this.messageFactory = messageFactory;\n169:     }\n170: \n171:     public MessageFactory getMessageFactory() {\n172:         return messageFactory;\n173:     }\n174: \n175:     /**\n176:      * To use the given LogFactory\n177:      */\n178:     public void setLogFactory(LogFactory logFactory) {\n179:         this.logFactory = logFactory;\n180:     }\n181: \n182:     public LogFactory getLogFactory() {\n183:         return logFactory;\n184:     }\n185: \n186:     /**\n187:      * To use the given MessageStoreFactory\n188:      */\n189:     public void setMessageStoreFactory(MessageStoreFactory messageStoreFactory) {\n190:         this.messageStoreFactory = messageStoreFactory;\n191:     }\n192: \n193:     public MessageStoreFactory getMessageStoreFactory() {\n194:         return messageStoreFactory;\n195:     }\n196: \n197:     public Map\u003cString, QuickfixjConfiguration\u003e getConfigurations() {\n198:         return configurations;\n199:     }\n200: \n201:     /**\n202:      * To use the given map of pre configured QuickFix configurations mapped to the key\n203:      */\n204:     public void setConfigurations(Map\u003cString, QuickfixjConfiguration\u003e configurations) {\n205:         this.configurations = configurations;\n206:     }\n207: \n208:     public boolean isLazyCreateEngines() {\n209:         return this.lazyCreateEngines;\n210:     }\n211: \n212:     /**\n213:      * If set to true, the engines will be created and started when needed (when first message is send)\n214:      */\n215:     public void setLazyCreateEngines(boolean lazyCreateEngines) {\n216:         this.lazyCreateEngines = lazyCreateEngines;\n217:     }\n218: \n219:     public boolean isEagerStopEngines() {\n220:         return eagerStopEngines;\n221:     }\n222: \n223:     /**\n224:      * Whether to eager stop engines when there are no active consumer or producers using the engine.\n225:      *\n226:      * For example when stopping a route, then the engine can be stopped as well. And when the route is started, then\n227:      * the engine is started again.\n228:      *\n229:      * This can be turned off to only stop the engines when Camel is shutdown.\n230:      */\n231:     public void setEagerStopEngines(boolean eagerStopEngines) {\n232:         this.eagerStopEngines = eagerStopEngines;\n233:     }\n234: \n235:     @Override\n236:     public void onCamelContextStarted(CamelContext camelContext, boolean alreadyStarted) throws Exception {\n237:         // only start quickfix engines when CamelContext have finished starting\n238:         lock.lock();\n239:         try {\n240:             for (QuickfixjEngine engine : engines.values()) {\n241:                 startQuickfixjEngine(engine);\n242:             }\n243:             for (Map.Entry\u003cString, QuickfixjEngine\u003e entry : provisionalEngines.entrySet()) {\n244:                 startQuickfixjEngine(entry.getValue());\n245:                 engines.put(entry.getKey(), entry.getValue());\n246:             }\n247:             provisionalEngines.clear();\n248:         } finally {\n249:             lock.unlock();\n250:         }\n251:     }\n252: \n253:     public void ensureEngineStarted(QuickfixjEngine engine) {\n254:         // only start engine after provisional engines is no longer in use\n255:         // as they are used for holding created engines during bootstrap of Camel\n256:         if (provisionalEngines.isEmpty()) {\n257:             ServiceHelper.startService(engine);\n258:         }\n259:     }\n260: }\n261: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/camel--1006f047@0c671f6f3a67e1d63502e00ea42b10fc10c15a57/-/blob/components/camel-quickfix/src/main/java/org/apache/camel/component/quickfixj/QuickfixjComponent.java"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: /*
