68:     @Override
69:     protected Endpoint createEndpoint(String uri, String remaining, Map<String, Object> parameters) throws Exception {
70:         // Look up the engine instance based on the settings file ("remaining")
71:         QuickfixjEngine engine;
72:         lock.lock();
73:         try {
74:             QuickfixjEndpoint endpoint = endpoints.get(uri);
75: 
76:             if (endpoint == null) {
77:                 engine = engines.get(remaining);
78:                 if (engine == null) {
79:                     engine = provisionalEngines.get(remaining);
80:                 }
