121:      * This option allows creating QuickFIX/J engine on demand. Value true means the engine is started when first
122:      * message is send or there's consumer configured in route definition. When false value is used, the engine is
123:      * started at the endpoint creation. When this parameter is missing, the value of component's property
124:      * lazyCreateEngines is being used.
125:      */
126:     public void setLazyCreateEngine(boolean lazyCreateEngine) {
127:         this.lazyCreateEngine = lazyCreateEngine;
128:     }
129: 
130:     @Override
131:     public Consumer createConsumer(Processor processor) throws Exception {
132:         LOG.info("Creating QuickFIX/J consumer: {}, ExchangePattern={}", sessionID != null ? sessionID : "No Session",
133:                 getExchangePattern());
134:         QuickfixjConsumer consumer = new QuickfixjConsumer(this, processor);
135:         configureConsumer(consumer);
136:         return consumer;
137:     }
138: 
139:     @Override
140:     public Producer createProducer() throws Exception {
141:         LOG.info("Creating QuickFIX/J producer: {}", sessionID != null ? sessionID : "No Session");
142:         if (isWildcarded()) {
143:             throw new ResolveEndpointFailedException("Cannot create consumer on wildcarded session identifier: " + sessionID);
144:         }
145:         return new QuickfixjProducer(this);
146:     }
147: 
148:     protected void addConsumer(QuickfixjConsumer consumer) {
149:         consumers.add(consumer);
150:         engine.incRefCount();
151:         getComponent().ensureEngineStarted(engine);
152:     }
153: 
154:     protected void removeConsumer(QuickfixjConsumer consumer) {
155:         consumers.remove(consumer);
156:         int count = engine.decRefCount();
157:         if (count <= 0 && getComponent().isEagerStopEngines()) {
158:             LOG.info("Stopping QuickFIX/J Engine: {} no longer active in use", engine.getUri());
159:             ServiceHelper.stopService(engine);
160:         }
161:     }
162: 
163:     protected void addProducer() {
164:         engine.incRefCount();
165:         getComponent().ensureEngineStarted(engine);
166:     }
167: 
168:     protected void removeProducer() {
169:         int count = engine.decRefCount();
170:         if (count <= 0 && getComponent().isEagerStopEngines()) {
171:             LOG.info("Stopping QuickFIX/J Engine: {} no longer active in use", engine.getUri());
172:             ServiceHelper.stopService(engine);
173:         }
174:     }
175: 
176:     @Override
177:     public void onEvent(QuickfixjEventCategory eventCategory, SessionID sessionID, Message message) throws Exception {
178:         if (this.sessionID == null || isMatching(sessionID)) {
179:             for (QuickfixjConsumer consumer : consumers) {
180:                 Exchange exchange
181:                         = QuickfixjConverters.toExchange(consumer, sessionID, message, eventCategory, getExchangePattern());
182:                 try {
183:                     consumer.onExchange(exchange);
184:                     Exception cause = exchange.getException();
185:                     if (cause != null) {
186:                         throw cause;
187:                     }
188:                 } finally {
189:                     consumer.releaseExchange(exchange, false);
190:                 }
191:             }
192:         }
193:     }
194: 
195:     private boolean isMatching(SessionID sessionID) {
196:         if (this.sid.equals(sessionID)) {
197:             return true;
198:         }
199:         return isMatching(this.sid.getBeginString(), sessionID.getBeginString())
200:                 && isMatching(this.sid.getSenderCompID(), sessionID.getSenderCompID())
201:                 && isMatching(this.sid.getSenderSubID(), sessionID.getSenderSubID())
202:                 && isMatching(this.sid.getSenderLocationID(), sessionID.getSenderLocationID())
203:                 && isMatching(this.sid.getTargetCompID(), sessionID.getTargetCompID())
204:                 && isMatching(this.sid.getTargetSubID(), sessionID.getTargetSubID())
205:                 && isMatching(this.sid.getTargetLocationID(), sessionID.getTargetLocationID());
206:     }
207: 
208:     private boolean isMatching(String s1, String s2) {
209:         return s1.isEmpty() || s1.equals("*") || s1.equals(s2);
210:     }
211: 
212:     private boolean isWildcarded() {
213:         if (sid == null) {
214:             return false;
215:         }
216:         return sid.getBeginString().equals("*")
217:                 || sid.getSenderCompID().equals("*")
218:                 || sid.getSenderSubID().equals("*")
219:                 || sid.getSenderLocationID().equals("*")
220:                 || sid.getTargetCompID().equals("*")
221:                 || sid.getTargetSubID().equals("*")
222:                 || sid.getTargetLocationID().equals("*");
223:     }
224: 
225:     @Override
226:     public boolean isMultipleConsumersSupported() {
227:         return true;
228:     }
229: 
230:     /**
231:      * Initializing and starts the engine if it wasn't initialized so far.
232:      */
233:     public void ensureInitialized() throws Exception {
234:         if (!engine.isInitialized()) {
235:             engineLock.lock();
236:             try {
237:                 if (!engine.isInitialized()) {
238:                     engine.initializeEngine();
239:                     ServiceHelper.startService(engine);
240:                 }
241:             } finally {
242:                 engineLock.unlock();
243:             }
244:         }
245:     }
246: 
247:     public QuickfixjEngine getEngine() {
248:         return engine;
249:     }
250: 
251:     @Override
252:     protected void doStop() throws Exception {
253:         // clear list of consumers
254:         consumers.clear();
255:     }
256: }
