{"meta": null, "content": [{"type": "text", "text": "{"content":"1: /*\n2:  * Licensed to the Apache Software Foundation (ASF) under one or more\n3:  * contributor license agreements.  See the NOTICE file distributed with\n4:  * this work for additional information regarding copyright ownership.\n5:  * The ASF licenses this file to You under the Apache License, Version 2.0\n6:  * (the \"License\"); you may not use this file except in compliance with\n7:  * the License.  You may obtain a copy of the License at\n8:  *\n9:  *      http://www.apache.org/licenses/LICENSE-2.0\n10:  *\n11:  * Unless required by applicable law or agreed to in writing, software\n12:  * distributed under the License is distributed on an \"AS IS\" BASIS,\n13:  * WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n14:  * See the License for the specific language governing permissions and\n15:  * limitations under the License.\n16:  */\n17: package org.apache.camel.component.nats;\n18: \n19: import java.io.IOException;\n20: import java.time.Duration;\n21: import java.util.concurrent.ExecutorService;\n22: \n23: import io.nats.client.Connection;\n24: import io.nats.client.Connection.Status;\n25: import io.nats.client.Dispatcher;\n26: import io.nats.client.JetStreamApiException;\n27: import io.nats.client.JetStreamManagement;\n28: import io.nats.client.JetStreamSubscription;\n29: import io.nats.client.Message;\n30: import io.nats.client.MessageHandler;\n31: import io.nats.client.PullSubscribeOptions;\n32: import io.nats.client.PushSubscribeOptions;\n33: import io.nats.client.api.ConsumerConfiguration;\n34: import io.nats.client.api.StreamConfiguration;\n35: import org.apache.camel.Exchange;\n36: import org.apache.camel.Processor;\n37: import org.apache.camel.spi.HeaderFilterStrategy;\n38: import org.apache.camel.support.DefaultConsumer;\n39: import org.apache.camel.util.ObjectHelper;\n40: import org.slf4j.Logger;\n41: import org.slf4j.LoggerFactory;\n42: \n43: public class NatsConsumer extends DefaultConsumer {\n44: \n45:     private static final Logger LOG = LoggerFactory.getLogger(NatsConsumer.class);\n46: \n47:     private final Processor processor;\n48:     private ExecutorService executor;\n49:     private Connection connection;\n50:     private Dispatcher dispatcher;\n51:     private boolean active;\n52:     private JetStreamSubscription jetStreamSubscription;\n53: \n54:     public NatsConsumer(NatsEndpoint endpoint, Processor processor) {\n55:         super(endpoint, processor);\n56:         this.processor = processor;\n57:     }\n58: \n59:     @Override\n60:     public NatsEndpoint getEndpoint() {\n61:         return (NatsEndpoint) super.getEndpoint();\n62:     }\n63: \n64:     @Override\n65:     protected void doStart() throws Exception {\n66:         super.doStart();\n67:         LOG.debug(\"Starting Nats Consumer\");\n68:         this.executor = this.getEndpoint().createExecutor(this);\n69: \n70:         LOG.debug(\"Getting Nats Connection\");\n71:         this.connection = this.getEndpoint().getConfiguration().getConnection() != null\n72:                 ? this.getEndpoint().getConfiguration().getConnection()\n73:                 : this.getEndpoint().getConnection();\n74: \n75:         this.executor.submit(new NatsConsumingTask(this.connection, this.getEndpoint().getConfiguration()));\n76:     }\n77: \n78:     @Override\n79:     protected void doStop() throws Exception {\n80:         final NatsConfiguration configuration = this.getEndpoint().getConfiguration();\n81: \n82:         if (configuration.isFlushConnection() \u0026\u0026 ObjectHelper.isNotEmpty(this.connection)) {\n83:             LOG.debug(\"Flushing Messages before stopping\");\n84:             this.connection.flush(Duration.ofMillis(configuration.getFlushTimeout()));\n85:         }\n86: \n87:         if (ObjectHelper.isNotEmpty(this.dispatcher)) {\n88:             try {\n89:                 this.dispatcher.unsubscribe(configuration.getTopic());\n90:             } catch (final Exception e) {\n91:                 this.getExceptionHandler().handleException(\"Error during unsubscribing\", e);\n92:             }\n93:         }\n94: \n95:         LOG.debug(\"Stopping Nats Consumer\");\n96:         if (this.executor != null) {\n97:             if (this.getEndpoint() != null \u0026\u0026 this.getEndpoint().getCamelContext() != null) {\n98:                 this.getEndpoint().getCamelContext().getExecutorServiceManager().shutdownNow(this.executor);\n99:             } else {\n100:                 this.executor.shutdownNow();\n101:             }\n102:         }\n103:         this.executor = null;\n104: \n105:         if (ObjectHelper.isEmpty(configuration.getConnection()) \u0026\u0026 ObjectHelper.isNotEmpty(this.connection)) {\n106:             LOG.debug(\"Closing Nats Connection\");\n107:             if (!this.connection.getStatus().equals(Status.CLOSED)) {\n108:                 this.connection.close();\n109:             }\n110:         }\n111:         super.doStop();\n112:     }\n113: \n114:     public boolean isActive() {\n115:         return this.active;\n116:     }\n117: \n118:     public void setActive(boolean active) {\n119:         this.active = active;\n120:     }\n121: \n122:     class NatsConsumingTask implements Runnable {\n123: \n124:         private final Connection connection;\n125:         private final NatsConfiguration configuration;\n126: \n127:         NatsConsumingTask(Connection connection, NatsConfiguration configuration) {\n128:             this.connection = connection;\n129:             this.configuration = configuration;\n130:         }\n131: \n132:         @Override\n133:         public void run() {\n134:             try {\n135:                 NatsConfiguration config = getEndpoint().getConfiguration();\n136:                 String topic = config.getTopic();\n137:                 String queueName = config.getQueueName();\n138:                 String maxMessagesStr = config.getMaxMessages();\n139:                 Integer maxMessages = null;\n140:                 if (ObjectHelper.isNotEmpty(maxMessagesStr)) {\n141:                     maxMessages = Integer.parseInt(maxMessagesStr);\n142:                 }\n143: \n144:                 if (config.isJetstreamEnabled() \u0026\u0026 connection.getServerInfo().isJetStreamAvailable()) {\n145:                     setupJetStreamConsumer(topic, queueName);\n146:                 } else {\n147:                     setupStandardNatsConsumer(topic, queueName, maxMessages);\n148:                 }\n149:             } catch (final Exception e) {\n150:                 NatsConsumer.this.getExceptionHandler().handleException(\"Error during processing\", e);\n151:             }\n152: \n153:         }\n154: \n155:         private void setupJetStreamConsumer(String topic, String queueName) throws IOException, JetStreamApiException {\n156:             String streamName = this.configuration.getJetstreamName();\n157:             String durableName = this.configuration.getDurableName();\n158: \n159:             String subscriptionType = this.configuration.isPullSubscription() ? \"PULL\" : \"PUSH\";\n160:             LOG.debug(\"Setting up JetStream {}/{} consumer for stream: '{}', subject: {}\",\n161:                     subscriptionType,\n162:                     ObjectHelper.isNotEmpty(durableName)\n163:                             ? String.format(\"DURABLE, durableName: '%s'\", durableName) : \"EPHEMERAL\",\n164:                     streamName,\n165:                     this.configuration.getTopic());\n166: \n167:             JetStreamManagement jsm = connection.jetStreamManagement();\n168:             if (streamExists(jsm, streamName)) {\n169:                 LOG.debug(\"JetStream stream '{}' already exists. Skipping creation.\", streamName);\n170:             } else {\n171:                 LOG.debug(\"Creating JetStream {}\", streamName);\n172:                 StreamConfiguration streamConfig = StreamConfiguration.builder()\n173:                         .name(streamName)\n174:                         .subjects(topic)\n175:                         .build();\n176:                 jsm.addStream(streamConfig);\n177:                 LOG.info(\"JetStream stream '{}' created successfully.\", streamName);\n178:             }\n179: \n180:             ConsumerConfiguration cc = configuration.getConsumerConfiguration();\n181:             if (cc == null) {\n182:                 ConsumerConfiguration.Builder ccBuilder = ConsumerConfiguration.builder();\n183:                 ccBuilder.deliverSubject(null);\n184:                 if (durableName != null) {\n185:                     ccBuilder.durable(durableName + \"-durable\");\n186:                 }\n187:                 cc = ccBuilder.build();\n188:             }\n189: \n190:             CamelNatsMessageHandler messageHandler = new CamelNatsMessageHandler();\n191:             NatsConsumer.this.dispatcher = this.connection.createDispatcher(messageHandler);\n192: \n193:             if (this.configuration.isPullSubscription()) {\n194:                 PullSubscribeOptions pullOptions = PullSubscribeOptions.builder()\n195:                         .configuration(cc)\n196:                         .build();\n197: \n198:                 NatsConsumer.this.jetStreamSubscription = this.connection.jetStream().subscribe(\n199:                         NatsConsumer.this.getEndpoint().getConfiguration().getTopic(),\n200:                         dispatcher,\n201:                         messageHandler,\n202:                         pullOptions);\n203:             } else {\n204:                 PushSubscribeOptions pushOptions = PushSubscribeOptions.builder()\n205:                         .configuration(cc)\n206:                         .deliverGroup(queueName)\n207:                         .build();\n208: \n209:                 NatsConsumer.this.jetStreamSubscription = this.connection.jetStream().subscribe(\n210:                         NatsConsumer.this.getEndpoint().getConfiguration().getTopic(),\n211:                         queueName,\n212:                         dispatcher,\n213:                         messageHandler,\n214:                         true,\n215:                         pushOptions);\n216:             }\n217: \n218:             NatsConsumer.this.setActive(true);\n219:         }\n220: \n221:         private void setupStandardNatsConsumer(String topic, String queueName, Integer maxMessages) {\n222:             LOG.debug(\"Setting up standard NATS consumer for subject: {}\", topic);\n223:             NatsConsumer.this.dispatcher = connection.createDispatcher(new CamelNatsMessageHandler());\n224:             if (ObjectHelper.isNotEmpty(queueName)) {\n225:                 NatsConsumer.this.dispatcher = NatsConsumer.this.dispatcher.subscribe(topic, queueName);\n226:             } else {\n227:                 NatsConsumer.this.dispatcher = NatsConsumer.this.dispatcher.subscribe(topic);\n228:             }\n229:             if (maxMessages != null) {\n230:                 NatsConsumer.this.dispatcher.unsubscribe(topic, maxMessages);\n231:             }\n232:             if (NatsConsumer.this.dispatcher.isActive()) {\n233:                 NatsConsumer.this.setActive(true);\n234:             }\n235:         }\n236: \n237:         class CamelNatsMessageHandler implements MessageHandler {\n238: \n239:             @Override\n240:             public void onMessage(Message msg) throws InterruptedException {\n241:                 LOG.debug(\"Received Message: {}\", msg);\n242:                 final Exchange exchange = NatsConsumer.this.createExchange(false);\n243:                 try {\n244:                     exchange.getIn().setBody(msg.getData());\n245:                     exchange.getIn().setHeader(NatsConstants.NATS_REPLY_TO, msg.getReplyTo());\n246:                     exchange.getIn().setHeader(NatsConstants.NATS_SID, msg.getSID());\n247:                     exchange.getIn().setHeader(NatsConstants.NATS_SUBJECT, msg.getSubject());\n248:                     exchange.getIn().setHeader(NatsConstants.NATS_QUEUE_NAME, msg.getSubscription().getQueueName());\n249:                     exchange.getIn().setHeader(NatsConstants.NATS_MESSAGE_TIMESTAMP, System.currentTimeMillis());\n250:                     if (msg.isStatusMessage() \u0026\u0026 msg.getStatus() != null) {\n251:                         exchange.getIn().setHeader(NatsConstants.NATS_STATUS_CODE, msg.getStatus().getCode());\n252:                         exchange.getIn().setHeader(NatsConstants.NATS_STATUS_ERROR, msg.getStatus().getMessage());\n253:                     }\n254:                     if (msg.getHeaders() != null) {\n255:                         final HeaderFilterStrategy strategy = NatsConsumer.this.getEndpoint()\n256:                                 .getConfiguration()\n257:                                 .getHeaderFilterStrategy();\n258:                         msg.getHeaders().entrySet().forEach(entry -\u003e {\n259:                             if (!strategy.applyFilterToExternalHeaders(entry.getKey(), entry.getValue(), exchange)) {\n260:                                 if (entry.getValue().size() == 1) {\n261:                                     // going from camel to nats add all headers in lists, so we extract them in the opposite\n262:                                     // way if it contains a single value\n263:                                     exchange.getIn().setHeader(entry.getKey(), entry.getValue().get(0));\n264:                                 } else {\n265:                                     exchange.getIn().setHeader(entry.getKey(), entry.getValue());\n266:                                 }\n267:                             } else {\n268:                                 LOG.debug(\"Excluding header {} as per strategy\", entry.getKey());\n269:                             }\n270:                         });\n271:                     }\n272:                     NatsConsumer.this.processor.process(exchange);\n273: \n274:                     // is there a reply?\n275:                     if (!NatsConsumingTask.this.configuration.isReplyToDisabled()\n276:                             \u0026\u0026 msg.getReplyTo() != null \u0026\u0026 msg.getConnection() != null) {\n277:                         final Connection con = msg.getConnection();\n278:                         final byte[] data = exchange.getMessage().getBody(byte[].class);\n279:                         if (data != null) {\n280:                             LOG.debug(\"Publishing replyTo: {} message\", msg.getReplyTo());\n281:                             con.publish(msg.getReplyTo(), data);\n282:                         }\n283:                     }\n284:                 } catch (final Exception e) {\n285:                     NatsConsumer.this.getExceptionHandler().handleException(\"Error during processing\", exchange, e);\n286:                 } finally {\n287:                     NatsConsumer.this.releaseExchange(exchange, false);\n288:                 }\n289:             }\n290:         }\n291:     }\n292: \n293:     private boolean streamExists(JetStreamManagement jsm, String streamName) throws IOException, JetStreamApiException {\n294:         try {\n295:             jsm.getStreamInfo(streamName);\n296:             return true;\n297:         } catch (JetStreamApiException jsae) {\n298:             if (jsae.getErrorCode() == 404) {\n299:                 return false;\n300:             }\n301:             throw jsae;\n302:         }\n303:     }\n304: \n305: }\n306: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/camel--1006f047@0c671f6f3a67e1d63502e00ea42b10fc10c15a57/-/blob/components/camel-nats/src/main/java/org/apache/camel/component/nats/NatsConsumer.java"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: /*
