 .headers(this.buildHeaders(exchange));\n90:             final CompletableFuture\u003cMessage\u003e requestFuture = this.connection.request(builder.build());\n91:             final CompletableFuture timeoutFuture = this.failAfter(exchange,\n92:                     Duration.ofMillis(config.getRequestTimeout()));\n93:             CompletableFuture.anyOf(requestFuture, timeoutFuture).whenComplete((message, e) -\u003e {\n94:                 if (e == null) {\n95:                     final Message msg = (Message) message;\n96:                     exchange.getMessage().setBody(msg.getData());\n97:                     exchange.getMessage().setHeader(NatsConstants.NATS_REPLY_TO, msg.getReplyTo());\n98:                     exchange.getMessage().setHeader(NatsConstants.NATS_SID, msg.getSID());\n99:                     exchange.getMessage().setHeader(NatsConstants.NATS_SUBJECT, msg.getSubject());\n100:                     exchange.getMessage().setHeader(NatsConstants.NATS_QUEUE_NAME, msg.getSubscription().getQueueName());\n101:                     exchange.getMessage().setHeader(NatsConstants.NATS_MESSAGE_TIMESTAMP, System.currentTimeMillis());\n102:                 } else {\n103:                     exchange.setException(e.getCause());\n104:                 }\n105:                 callback.done(false);\n106:                 if (!requestFuture.isDone()) {\n107:                     requestFuture.cancel(true);\n108:                 }\n109:                 if (!timeoutFuture.isDone()) {\n110:                     timeoutFuture.cancel(true);\n111:                 }\n112:             });\n113:             return false;\n114:         } else {\n115:             LOG.debug(\"Publishing to subject: {}\", config.getTopic());\n116:             try {\n117:                 if (config.isJetstreamEnabled() \u0026\u0026 this.connection.getServerInfo().isJetStreamAvailable()) {\n118:                     publishWithJetStream(config, body, exchange);\n119:                 } else {\n120:                     publishWithoutJetStream(config, body, exchange);\n121:                 }\n122:             } catch (Exception e) {\n123:                 exchange.setException(e);\n124:                 callback.done(true);\n125:                 return true;\n126:             }\n127:             callback.done(true);\n128:             return true;\n129:         }\n130:     }\n131: \n132:     private Headers buildHeaders(final Exchange exchange) {\n133:         final Headers headers = new Headers();\n134:         final HeaderFilterStrategy filteringStrategy = this.getEndpoint().getConfiguration().getHeaderFilterStrategy();\n135:         exchange.getIn().getHeaders().forEach((key, value) -\u003e {\n136:             if (!filteringStrategy.applyFilterToCamelHeaders(key, value, exchange)) {\n137:                 String headerValue;\n138:                 if (value instanceof byte[] byteArray) {\n139:                     headerValue = new String(byteArray, StandardCharsets.UTF_8);\n140:                 } else {\n141:                     headerValue = String.valueOf(value);\n142:                 }\n143:                 if (headers.get(key) != null) {\n144:                     headers.get(key).add(headerValue);\n145:                 } else {\n146:                     headers.add(key, headerValue);\n147:                 }\n148:             } else {\n149:                 LOG.debug(\"Excluding header {} as per strategy\", key);\n150:             }\n151: \n152:         });\n153:         return headers;\n154:     }\n155: \n156:     private \u003cT\u003e CompletableFuture\u003cT\u003e failAfter(Exchange exchange, Duration duration) {\n157:         final CompletableFuture\u003cT\u003e future = new CompletableFuture\u003c\u003e();\n158:         this.scheduler.schedule(() -\u003e {\n159:             final ExchangeTimedOutException ex = new ExchangeTimedOutException(exchange, duration.toMillis());\n160:             return future.completeExceptionally(ex);\n161:         }, duration.toNanos(), Ti