50: public class NatsProducer extends DefaultAsyncProducer {
51: 
52:     private static final Logger LOG = LoggerFactory.getLogger(NatsProducer.class);
53: 
54:     private final ExecutorServiceManager executorServiceManager;
55:     private ScheduledExecutorService scheduler;
56:     private Connection connection;
57: 
58:     public NatsProducer(NatsEndpoint endpoint) {
59:         super(endpoint);
60:         this.executorServiceManager = endpoint.getCamelContext().getExecutorServiceManager();
61:     }
62: 
63:     @Override
64:     public NatsEndpoint getEndpoint() {
65:         return (NatsEndpoint) super.getEndpoint();
66:     }
67: 
68:     @Override
69:     public boolean process(Exchange exchange, AsyncCallback callback) {
70:         final NatsConfiguration config = this.getEndpoint().getConfiguration();
71:         byte[] body = exchange.getIn().getBody(byte[].class);
72:         if (body == null) {
73:             // fallback to use string
74:             try {
75:                 body = exchange.getIn().getMandatoryBody(String.class).getBytes();
76:             } catch (final InvalidPayloadException e) {
77:                 exchange.setException(e);
78:                 callback.done(true);
79:                 return true;
80:             }
81:         }
82: 
83:         if (exchange.getPattern().isOutCapable()) {
84:             LOG.debug("Requesting to topic: {}", config.getTopic());
85: 
86:             final NatsMessage.Builder builder = NatsMessage.builder()
87:                     .data(body)
88:                     .subject(config.getTopic())
89:                     .headers(this.buildHeaders(exchange));
90:             final CompletableFuture<Message> requestFuture = this.connection.request(builder.build());
91:             final CompletableFuture timeoutFuture = this.failAfter(exchange,
92:                     Duration.ofMillis(config.getRequestTimeout()));
93:             CompletableFuture.anyOf(requestFuture, timeoutFuture).whenComplete((message, e) -> {
94:                 if (e == null) {
95:                     final Message msg = (Message) message;
96:                     exchange.getMessage().setBody(msg.getData());
97:                     exchange.getMessage().setHeader(NatsConstants.NATS_REPLY_TO, msg.getReplyTo());
98:                     exchange.getMessage().setHeader(NatsConstants.NATS_SID, msg.getSID());
99:                     exchange.getMessage().setHeader(NatsConstants.NATS_SUBJECT, msg.getSubject());
100:                     exchange.getMessage().setHeader(NatsConstants.NATS_QUEUE_NAME, msg.getSubscription().getQueueName());
101:                     exchange.getMessage().setHeader(NatsConstants.NATS_MESSAGE_TIMESTAMP, System.currentTimeMillis());
102:                 } else {
103:                     exchange.setException(e.getCause());
104:                 }
105:                 callback.done(false);
106:                 if (!requestFuture.isDone()) {
107:                     requestFuture.cancel(true);
108:                 }
109:                 if (!timeoutFuture.isDone()) {
110:                     timeoutFuture.cancel(true);
111:                 }
112:             });
113:             return false;
114:         } else {
115:             LOG.debug("Publishing to subject: {}", config.getTopic());
116:             try {
117:                 if (config.isJetstreamEnabled() && this.connection.getServerInfo().isJetStreamAvailable()) {
118:                     publishWithJetStream(config, body, exchange);
119:                 } else {
120:                     publishWithoutJetStream(config, body, exchange);
121:                 }
122:             } catch (Exception e) {
123:                 exchange.setException(e);
124:                 callback.done(true);
125:                 return true;
126:             }
127:             callback.done(true);
128:             return true;
129:         }
130:     }
131: 
132:     private Headers buildHeaders(final Exchange exchange) {
133:         final Headers headers = new Headers();
134:         final HeaderFilterStrategy filteringStrategy = this.getEndpoint().getConfiguration().getHeaderFilterStrategy();
135:         exchange.getIn().getHeaders().forEach((key, value) -> {
136:             if (!filteringStrategy.applyFilterToCamelHeaders(key, value, exchange)) {
137:                 String headerValue;
138:                 if (value instanceof byte[] byteArray) {
139:                     headerValue = new String(byteArray, StandardCharsets.UTF_8);
140:                 } else {
141:                     headerValue = String.valueOf(value);
142:                 }
143:                 if (headers.get(key) != null) {
144:                     headers.get(key).add(headerValue);
145:                 } else {
146:                     headers.add(key, headerValue);
147:                 }
148:             } else {
149:                 LOG.debug("Excluding header {} as per strategy", key);
150:             }
151: 
152:         });
153:         return headers;
154:     }
155: 
156:     private <T> CompletableFuture<T> failAfter(Exchange exchange, Duration duration) {
157:         final CompletableFuture<T> future = new CompletableFuture<>();
158:         this.scheduler.schedule(() -> {
159:             final ExchangeTimedOutException ex = new ExchangeTimedOutException(exchange, duration.toMillis());
160:             return future.completeExceptionally(ex);
161:         }, duration.toNanos(), TimeUnit.NANOSECONDS);
162:         return future;
163:     }
164: 
165:     @Override
166:     protected void doStart() throws Exception {
167:         // try to lookup a pool first based on profile
168:         ThreadPoolProfile profile
169:                 = this.executorServiceManager.getThreadPoolProfile(NatsConstants.NATS_REQUEST_TIMEOUT_THREAD_PROFILE_NAME);
170:         if (profile == null) {
171:             profile = this.executorServiceManager.getDefaultThreadPoolProfile();
172:         }
173:         this.scheduler
174:                 = this.executorServiceManager.newScheduledThreadPool(this,
175:                         NatsConstants.NATS_REQUEST_TIMEOUT_THREAD_PROFILE_NAME, profile);
176:         super.doStart();
177:         LOG.debug("Starting Nats Producer");
178: 
179:         LOG.debug("Getting Nats Connection");
180:         this.connection = this.getEndpoint().getConfiguration().getConnection() != null
181:                 ? this.getEndpoint().getConfiguration().getConnection()
182:                 : this.getEndpoint().getConnection();
183:     }
184: 
185:     @Override
186:     protected void doStop() throws Exception {
187:         if (this.scheduler != null) {
188:             this.executorServiceManager.shutdownNow(this.scheduler);
189:         }
190:         LOG.debug("Stopping Nats Producer");
191:         if (ObjectHelper.isEmpty(this.getEndpoint().getConfiguration().getConnection())) {
192:             LOG.debug("Closing Nats Connection");
193:             if (this.connection != null && !this.connection.getStatus().equals(Status.CLOSED)) {
194:                 if (this.getEndpoint().getConfiguration().isFlushConnection()) {
195:                     LOG.debug("Flushing Nats Connection");
196:                     this.connection.flush(Duration.ofMillis(this.getEndpoint().getConfiguration().getFlushTimeout()));
197:                 }
198:                 this.connection.close();
199:             }
200:         }
201:         super.doStop();
202:     }
203: 
204:     private void publishWithJetStream(NatsConfiguration config, final byte[] body, final Exchange exchange) throws Exception {
205:         LOG.debug("JetStream is available");
206:         JetStreamManagement jsm;
207:         JetStream js;
208:         try {
209:             jsm = this.connection.jetStreamManagement();
210:             js = jsm.jetStream();
211:             if (js == null) {
212:                 jsm.addStream(StreamConfiguration.builder()
213:                         .name(config.getJetstreamName())
214:                         .subjects(config.getTopic())
215:                         .build());
216:                 js = jsm.jetStream();
217:             }
218:         } catch (IOException | JetStreamApiException e) {
219:             throw new Exception("Failed to initialize JetStream: " + e.getMessage(), e);
220:         }
221: 
222:         final NatsMessage.Builder builder = NatsMessage.builder()
223:                 .data(body)
224:                 .subject(config.getTopic())
225:                 .headers(this.buildHeaders(exchange));
226: 
227:         if (ObjectHelper.isNotEmpty(config.getReplySubject())) {
228:             final String replySubject = config.getReplySubject();
229:             builder.replyTo(replySubject);
230:         }
231:         final Message jetStreamMessage = builder.build();
232: 
233:         PublishAck pa;
234:         if (config.isJetstreamAsync()) {
235:             CompletableFuture<PublishAck> future = js.publishAsync(jetStreamMessage);
236:             try {
237:                 pa = future.get(config.getRequestTimeout(), TimeUnit.MILLISECONDS);
238:             } catch (InterruptedException | ExecutionException | TimeoutException e) {
239:                 throw new Exception("Failed to publish message asynchronously with JetStream: " + e.getMessage(), e);
240:             }
241:             LOG.debug("Publish Sequence async: {}", pa.getSeqno());
242:         } else {
243:             try {
244:                 pa = js.publish(jetStreamMessage);
245:             } catch (IOException | JetStreamApiException e) {
246:                 throw new Exception("Failed to publish message synchronously with JetStream: " + e.getMessage(), e);
247:             }
248:             LOG.debug("Publish Sequence synchronously: {}", pa.getSeqno());
249:         }
250:     }
251: 
252:     private void publishWithoutJetStream(NatsConfiguration config, final byte[] body, final Exchange exchange) {
253:         final NatsMessage.Builder builder = NatsMessage.builder()
254:                 .data(body)
255:                 .subject(config.getTopic())
256:                 .headers(this.buildHeaders(exchange));
257: 
258:         if (ObjectHelper.isNotEmpty(config.getReplySubject())) {
259:             final String replySubject = config.getReplySubject();
260:             builder.replyTo(replySubject);
261:         }
262:         this.connection.publish(builder.build());
263:     }
264: 
265: }
