import quickfix.MessageFactory;
import quickfix.MessageStoreFactory;
import quickfix.RejectLogon;
import quickfix.SessionID;
import quickfix.SessionSettings;
import quickfix.SocketAcceptor;
import quickfix.UnsupportedMessageType;
import quickfix.field.MsgType;
import quickfix.field.SenderCompID;
import quickfix.field.TargetCompID;

/**
 * FIX consumer that receives inbound FIX messages and feeds them into Camel routes.
 * <p/>
 * Implements the QuickFIX/J {@link Application} interface to receive FIX session events
 * and messages, then routes them as Camel exchanges.
 */
public class FixConsumer extends DefaultConsumer implements Application {

    private static final Logger LOG = LoggerFactory.getLogger(FixConsumer.class);

    private SocketAcceptor acceptor;

    public FixConsumer(FixEndpoint endpoint, Processor processor) {
        super(endpoint, processor);
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();
        LOG.info("Starting FIX consumer for session: {}", getEndpoint().getConfiguration().getSessionID());

        SessionSettings settings = loadSessionSettings();
        MessageStoreFactory storeFactory = new FileStoreFactory(settings);
        MessageFactory messageFactory = new DefaultMessageFactory();

        acceptor = new SocketAcceptor(this, storeFactory, settings, messageFactory);
        acceptor.start();
        LOG.info("FIX acceptor started");
    }

    @Override
    protected void doStop() throws Exception {
        LOG.info("Stopping FIX consumer for session: {}", getEndpoint().getConfiguration().getSessionID());
        if (acceptor != null) {
            acceptor.stop();
            acceptor = null;
        }
        super.doStop();
    }

    private SessionSettings loadSessionSettings() throws ConfigError {
        FixConfiguration config = getEndpoint().getConfiguration();

        if (config.getConfigFile() != null) {
            try {
                InputStream is = ResourceHelper.resolveResourceAsInputStream(
                        getEndpoint().getCamelContext(), config.getConfigFile());
                return new SessionSettings(is);
            } catch (Exception e) {
                throw new ConfigError("Failed to load FIX configuration file: " + config.getConfigFile(), e);
            }
        }

        // Build settings programmatically from configuration
        SessionSettings settings = new SessionSettings();
        SessionID sessionID = buildSessionID(config);

        settings.setString(sessionID, "ConnectionType", "acceptor");
        settings.setString(sessionID, "BeginString", config.getFixVersion());
        settings.setString(sessionID, "SenderCompID", config.getSenderCompID() != null ? config.getSenderCompID() : "SENDER");
        settings.setString(sessionID, "TargetCompID", config.getTargetCompID() != null ? config.getTargetCompID() : "TARGET");
        settings.setLong(sessionID, "HeartBtInt", config.getHeartBeatInterval());
        settings.setLong(sessionID, "SocketAcceptPort", config.getSocketConnectPort());
        settings.setString(sessionID, "FileStorePath", "target/data/fix");
        settings.setString(sessionID, "StartTime", "00:00:00");
        settings.setString(sessionID, "EndTime", "00:00:00");
        settings.setString(sessionID, "UseDataDictionary", "N");

        return settings;
    }

    private SessionID buildSessionID(FixConfiguration config) {
        String sessionIDStr = config.getSessionID();
        if (sessionIDStr != null && sessionIDStr.contains(":") && sessionIDStr.contains("->")) {
            return new SessionID(sessionIDStr);
        }
        String beginString = config.getFixVersion() != null ? config.getFixVersion() : "FIX.4.2";
        String sender = config.getSenderCompID() != null ? config.getSenderCompID() : "SENDER";
        String target = config.getTargetCompID() != null ? config.getTargetCompID() : "TARGET";
        return new SessionID(beginString, sender, target);
    }

    // --- QuickFIX/J Application interface ---

    @Override
    public void onCreate(SessionID sessionId) {
        LOG.debug("FIX session created: {}", sessionId);
    }

    @Override
    public void onLogon(SessionID sessionId) {
        LOG.info("FIX session logged on: {}", sessionId);
    }

    @Override
    public void onLogout(SessionID sessionId) {
        LOG.info("FIX session logged out: {}", sessionId);
    }

    @Override
    public void toAdmin(Message message, SessionID sessionId) {
        // called for outbound admin messages (logon, heartbeat, etc.)
    }

    @Override
    public void fromAdmin(Message message, SessionID sessionId)
            throws FieldNotFound, IncorrectDataFormat, IncorrectTagValue, RejectLogon {
        // called for inbound admin messages
    }

    @Override
    public void toApp(Message message, SessionID sessionId) throws DoNotSend {
        // called for outbound application messages
    }

    @Override
    public void fromApp(Message message, SessionID sessionId)
            throws FieldNotFound, IncorrectDataFormat, IncorrectTagValue, UnsupportedMessageType {
        LOG.debug("Received FIX message from session {}: {}", sessionId, message);
        routeMessage(message, sessionId);
    }

    private void routeMessage(Message message, SessionID sessionId) {
        final Exchange exchange = createExchange(false);
        try {
            exchange.getIn().setBody(message);
            exchange.getIn().setHeader(FixConstants.FIX_SESSION_ID, sessionId.toString());

            try {
                String msgType = message.getHeader().getString(MsgType.FIELD);
                exchange.getIn().setHeader(FixConstants.FIX_MESSAGE_TYPE, msgType);
            } catch (FieldNotFound e) {
                LOG.debug("MsgType field not found in FIX message");
            }

            try {
                String senderCompID = message.getHeader().getString(SenderCompID.FIELD);
                exchange.getIn().setHeader(FixConstants.FIX_SENDER_COMP_ID, senderCompID);
            } catch (FieldNotFound e) {
                LOG.debug("SenderCompID field not found in FIX message");
            }

            try {
                String targetCompID = message.getHeader().getString(TargetCompID.FIELD);
                exchange.getIn().setHeader(FixConstants.FIX_TARGET_COMP_ID, targetCompID);
            } catch (FieldNotFound e) {
                LOG.debug("TargetCompID field not found in FIX message");
            }

            getProcessor().process(exchange);
        } catch (Exception e) {
            getExceptionHandler().handleException("Error processing FIX message", exchange, e);
        } finally {
            releaseExchange(exchange, false);
        }
    }
}

