    public boolean process(Exchange exchange, AsyncCallback callback) {
        try {
            Message message = exchange.getIn().getBody(Message.class);
            if (message == null) {
                exchange.setException(
                        new IllegalArgumentException("Exchange body must be a quickfix.Message instance"));
                callback.done(true);
                return true;
            }

            SessionID sessionID = resolveSessionID(exchange);
            LOG.debug("Sending FIX message to session {}: {}", sessionID, message);

            Session.sendToTarget(message, sessionID);
        } catch (SessionNotFound e) {
            exchange.setException(new RuntimeException("FIX session not found: " + e.getMessage(), e));
        } catch (Exception e) {
            exchange.setException(e);
        }

        callback.done(true);
        return true;
    }

    private SessionID resolveSessionID(Exchange exchange) {
        // Check if a session ID is provided in the exchange headers
        String sessionIDHeader = exchange.getIn().getHeader(FixConstants.FIX_SESSION_ID, String.class);
        if (sessionIDHeader != null) {
            return new SessionID(sessionIDHeader);
        }

        // Fall back to the endpoint configuration
        FixConfiguration config = getEndpoint().getConfiguration();
        String sessionIDStr = config.getSessionID();
        if (sessionIDStr != null && sessionIDStr.contains(":") && sessionIDStr.contains("->")) {
            return new SessionID(sessionIDStr);
        }

        String beginString = config.getFixVersion() != null ? config.getFixVersion() : "FIX.4.2";
        String sender = config.getSenderCompID() != null ? config.getSenderCompID() : "SENDER";
        String target = config.getTargetCompID() != null ? config.getTargetCompID() : "TARGET";
        return new SessionID(beginString, sender, target);
    }
}

