    47  /**
    48   * FIX consumer that receives inbound FIX messages and feeds them into Camel routes.
    49   * <p/>
    50   * Implements the QuickFIX/J {@link Application} interface to receive FIX session events
    51   * and messages, then routes them as Camel exchanges.
    52   */
    53  public class FixConsumer extends DefaultConsumer implements Application {
    54
    55      private static final Logger LOG = LoggerFactory.getLogger(FixConsumer.class);
    56
    57      private SocketAcceptor acceptor;
    58
    59      public FixConsumer(FixEndpoint endpoint, Processor processor) {
    60          super(endpoint, processor);
    61      }
    62
    63      @Override
    64      public FixEndpoint getEndpoint() {
    65          return (FixEndpoint) super.getEndpoint();
    66      }
    67
    68      @Override
    69      protected void doStart() throws Exception {
    70          super.doStart();
    71          LOG.info("Starting FIX consumer for session: {}", getEndpoint().getConfiguration().getSessionID());
    72
    73          SessionSettings settings = loadSessionSettings();
    74          MessageStoreFactory storeFactory = new FileStoreFactory(settings);
    75          MessageFactory messageFactory = new DefaultMessageFactory();
    76
    77          acceptor = new SocketAcceptor(this, storeFactory, settings, messageFactory);
    78          acceptor.start();
    79          LOG.info("FIX acceptor started");
    80      }
    81
    82      @Override
    83      protected void doStop() throws Exception {
    84          LOG.info("Stopping FIX consumer for session: {}", getEndpoint().getConfiguration().getSessionID());
    85          if (acceptor != null) {
    86              acceptor.stop();
    87              acceptor = null;
    88          }
    89          super.doStop();
    90      }
    91
    92      private SessionSettings loadSessionSettings() throws ConfigError {
    93          FixConfiguration config = getEndpoint().getConfiguration();
    94
    95          if (config.getConfigFile() != null) {
    96              try {
    97                  InputStream is = ResourceHelper.resolveResourceAsInputStream(
    98                          getEndpoint().getCamelContext(), config.getConfigFile());
    99                  return new SessionSettings(is);
   100              } catch (Exception e) {
   101                  throw new ConfigError("Failed to load FIX configuration file: " + config.getConfigFile(), e);
   102              }
   103          }
   104
   105          // Build settings programmatically from configuration
   106          SessionSettings settings = new SessionSettings();
   107          SessionID sessionID = buildSessionID(config);
   108
   109          settings.setString(sessionID, "ConnectionType", "acceptor");
   110          settings.setString(sessionID, "BeginString", config.getFixVersion());
   111          settings.setString(sessionID, "SenderCompID", config.getSenderCompID() != null ? config.getSenderCompID() : "SENDER");
   112          settings.setString(sessionID, "TargetCompID", config.getTargetCompID() != null ? config.getTargetCompID() : "TARGET");
   113          settings.setLong(sessionID, "HeartBtInt", config.getHeartBeatInterval());
   114          settings.setLong(sessionID, "SocketAcceptPort", config.getSocketConnectPort());
   115          settings.setString(sessionID, "FileStorePath", "target/data/fix");
   116          settings.setString(sessionID, "StartTime", "00:00:00");
   117          settings.setString(sessionID, "EndTime", "00:00:00");
   118          settings.setString(sessionID, "UseDataDictionary", "N");
   119
   120          return settings;
   121      }
   122
   123      private SessionID buildSessionID(FixConfiguration config) {
   124          String sessionIDStr = config.getSessionID();
   125          if (sessionIDStr != null && sessionIDStr.contains(":") && sessionIDStr.contains("->")) {
   126              return new SessionID(sessionIDStr);
   127          }
   128          String beginString = config.getFixVersion() != null ? config.getFixVersion() : "FIX.4.2";
   129          String sender = config.getSenderCompID() != null ? config.getSenderCompID() : "SENDER";
   130          String target = config.getTargetCompID() != null ? config.getTargetCompID() : "TARGET";
   131          return new SessionID(beginString, sender, target);
   132      }
   133
   134      // --- QuickFIX/J Application interface ---
   135
   136      @Override
   137      public void onCreate(SessionID sessionId) {
   138          LOG.debug("FIX session created: {}", sessionId);
   139      }
   140
   141      @Override
   142      public void onLogon(SessionID sessionId) {
   143          LOG.info("FIX session logged on: {}", sessionId);
   144      }
   145
   146      @Override
   147      public void onLogout(SessionID sessionId) {
   148          LOG.info("FIX session logged out: {}", sessionId);
   149      }
   150
   151      @Override
   152      public void toAdmin(Message message, SessionID sessionId) {
   153          // called for outbound admin messages (logon, heartbeat, etc.)
   154      }
   155
   156      @Override
   157      public void fromAdmin(Message message, SessionID sessionId)
   158              throws FieldNotFound, IncorrectDataFormat, IncorrectTagValue, RejectLogon {
   159          // called for inbound admin messages
   160      }
   161
   162      @Override
   163      public void toApp(Message message, SessionID sessionId) throws DoNotSend {
   164          // called for outbound application messages
   165      }
   166
   167      @Override
   168      public void fromApp(Message message, SessionID sessionId)
   169              throws FieldNotFound, IncorrectDataFormat, IncorrectTagValue, UnsupportedMessageType {
   170          LOG.debug("Received FIX message from session {}: {}", sessionId, message);
   171          routeMessage(message, sessionId);
   172      }
   173
   174      private void routeMessage(Message message, SessionID sessionId) {
   175          final Exchange exchange = createExchange(false);
   176          try {
   177              exchange.getIn().setBody(message);
   178              exchange.getIn().setHeader(FixConstants.FIX_SESSION_ID, sessionId.toString());
   179
   180              try {
   181                  String msgType = message.getHeader().getString(MsgType.FIELD);
   182                  exchange.getIn().setHeader(FixConstants.FIX_MESSAGE_TYPE, msgType);
   183              } catch (FieldNotFound e) {
   184                  LOG.debug("MsgType field not found in FIX message");
   185              }
   186
   187              try {
   188                  String senderCompID = message.getHeader().getString(SenderCompID.FIELD);
   189                  exchange.getIn().setHeader(FixConstants.FIX_SENDER_COMP_ID, senderCompID);
   190              } catch (FieldNotFound e) {
   191                  LOG.debug("SenderCompID field not found in FIX message");
   192              }
   193
   194              try {
   195                  String targetCompID = message.getHeader().getString(TargetCompID.FIELD);
   196                  exchange.getIn().setHeader(FixConstants.FIX_TARGET_COMP_ID, targetCompID);
   197              } catch (FieldNotFound e) {
   198                  LOG.debug("TargetCompID field not found in FIX message");
   199              }
   200
   201              getProcessor().process(exchange);
   202          } catch (Exception e) {
   203              getExceptionHandler().handleException("Error processing FIX message", exchange, e);
   204          } finally {
   205              releaseExchange(exchange, false);
   206          }
   207      }
   208  }

